solution_code:
#include <iostream>

class Animal {
public:
    virtual ~Animal() { std::cout << "~Animal\n"; }
};

class Dog : public Animal {
public:
    ~Dog() override { std::cout << "~Dog\n"; }
};

int main() {
    Animal* p = new Dog{};
    delete p;
    return 0;
}

