solution_code:
#include <iostream>

class Widget {
public:
    static int count;

    Widget() { ++count; }
    virtual ~Widget() { --count; }

    static int liveCount() { return count; }
};

int Widget::count = 0;

class Button : public Widget {
public:
    // inherits constructor and destructor from Widget
};

int main() {
    Widget* w1 = new Widget{};
    Widget* w2 = new Button{};
    std::cout << "Live: " << Widget::liveCount() << "\n";
    delete w1;
    delete w2;
    std::cout << "Live: " << Widget::liveCount() << "\n";
    return 0;
}
